  ('social-worker-moex-01571', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '問題解決模式（Problem-Solving Model）對於社會工作實務運作影響極其深遠。針對社會工作者 所運用的問題解決模式，下列敘述何者錯誤？', '["案主的問題並非是案主軟弱和不足所致", "案主無法有效地解決問題，是因為缺乏動機、機會或能力所致", "問題解決模式認為人生是一連串解決問題的過程", "問題解決模式重視案主早年經驗的影響力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01572', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一位失業單親父親並無親友支持系統，其居住的社區托育服務資源稀缺且昂貴。每次應徵工作 時，就將5歲的孩子獨留家中，而觸法。社會工作者在進行社區社會支持網絡評量時，其評估內 容不包括下列何者？', '["對正式支持體系的資源網絡結構評估", "對正式支持體系的資源功能限制評估", "對非正式支持體系發揮的支持功能評估", "對非正式支持體系應有的支持責任評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01573', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '增權觀點在美國的起源跟下列那一個族群密切相關？', '["低收入戶", "心理疾病患者", "少數民族", "老人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01574', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以女性為中心的工作原則，下列何者錯誤？', '["成立女性團體", "書寫與紀錄是制度的壓迫，釐清與確認不利女性政策與服務對於工作沒有助益", "鼓勵女性進入機構決策中心，建立代表機制", "運用有利於女性的社會工作理論與方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01575', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關「後現代觀點社會工作」的敘述，何者錯誤？', '["客觀性", "可能性", "主體性", "不確定性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01576', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '若一位社會工作者認為其工作價值主要是讓案主提升正直品格，過一種有德性的生活，且不依賴 政府。這是屬於下列那一種社會工作價值取向？', '["社會正義取向", "父權主義取向", "臨床取向", "無道德取向"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01577', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當一位以心理暨社會學派進行處遇的社會工作者對案主說出：「你有沒有注意到，每當公婆要來 家裡之前，你就向你先生發脾氣」。社會工作者使用的是什麼技術？', '["宣洩的技術", "支持性的技術", "直接影響的技術", "反映性討論的技術"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01578', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '小花正在提供婚姻諮商服務：先生的飲酒習慣嚴重影響夫妻關係。後來經小花轉介，先生參加戒 酒團體，並向小花及太太述說參加戒酒團體對他的幫助。然而，某一次婚姻諮商結束後，先生獨 自留下向小花表示自己並沒有參加戒酒團體，且飲酒量也愈來愈多，自己也不知道如何是好，但 是希望小花先不要跟太太說這件事情。下列敘述何者正確？', '["身為義務論者，為了保護太太在婚姻關係中免於被欺騙，小花應該主動揭露先生的欺騙行為", "身為行為的效益主義者，小花要尊重先生的隱私權，不應該向太太揭露", "身為規則的效益主義者，小花保留隱私資訊是可以被理解與接受的，因為這樣才不會影響先生 對小花的信賴", "身為效益主義者，小花可以選擇結束這個專業關係，避免被告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01579', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關臺灣的社會工作倫理守則之敘述，何者正確？①依據社會工作師法第 17 條所制定', '["97年3月28日內政部同意核備", "守則內所稱案主是指接受社會工作服務的個人、家庭與 團體", "社會工作師違反法令、社會工作師公會章程或本守則者，除法令另有處罰規定者外，並 不需要受到審議與其他處置", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01580', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的發展根基立基於公平正義等概念。從價值面向而言，社會工作是一門怎樣的專業？', '["規範性專業", "科學性專業", "工具性專業", "組織性專業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
